  3→/* ══════════════════════════════════════════════════════════════════════════
  4→   SIGNUP PAGE — Editorial Writing Platform Aesthetic
  5→   Matches LoginPage design system
  6→   ══════════════════════════════════════════════════════════════════════════ */
  7→
  8→.auth-shell {
  9→    display: grid;
 10→    grid-template-columns: 1fr 1fr;
 11→    min-height: 100svh;
 12→    background-color: var(--bg-primary);
 13→    color: var(--text-primary);
 14→    font-family: var(--font-ui);
 15→    overflow-x: hidden;
 16→}
 17→
 18→/* ── Left Panel: Brand Story ── */
 19→.auth-panel {
 20→    position: relative;
 21→    display: flex;
 22→    flex-direction: column;
 23→    justify-content: center;
 24→    padding: 64px 72px;
 25→    background: var(--bg-card);
 26→    border-right: 1px solid var(--border-card);
 27→    overflow: hidden;
 28→}
 29→
 30→/* Decorative ink blot shapes */
 31→.auth-panel::before {
 32→    content: '';
 33→    position: absolute;
 34→    width: 400px;
 35→    height: 400px;
 36→    border-radius: 47% 53% 61% 39% / 45% 51% 49% 55%;
 37→    background: radial-gradient(
 38→        ellipse at 30% 30%,
 39→        rgba(212, 168, 83, 0.08),
 40→        transparent 70%
 41→    );
 42→    top: -120px;
 43→    left: -100px;
 44→    animation: morph 20s ease-in-out infinite;
 45→}
 46→
 47→.auth-panel::after {
 48→    content: '';
 49→    position: absolute;
 50→    width: 300px;
 51→    height: 300px;
 52→    border-radius: 61% 39% 47% 53% / 49% 55% 45% 51%;
 53→    background: radial-gradient(
 54→        ellipse at 70% 60%,
 55→        rgba(212, 168, 83, 0.06),
 56→        transparent 70%
 57→    );
 58→    bottom: -80px;
 59→    right: 20px;
 60→    animation: morph 25s ease-in-out infinite reverse;
 61→}
 62→
 63→@keyframes morph {
 64→    0%, 100% { border-radius: 47% 53% 61% 39% / 45% 51% 49% 55%; }
 65→    25% { border-radius: 55% 45% 50% 50% / 60% 40% 60% 40%; }
 66→    50% { border-radius: 40% 60% 55% 45% / 50% 55% 45% 50%; }
 67→    75% { border-radius: 60% 40% 45% 55% / 45% 60% 40% 55%; }
 68→}
 69→
 70→.brand {
 71→    font-family: "Playfair Display", serif;
 72→    font-size: 1.1rem;
 73→    font-weight: 600;
 74→    letter-spacing: 0.18em;
 75→    text-transform: uppercase;
 76→    color: var(--accent-amber);
 77→    margin-bottom: 48px;
 78→    position: relative;
 79→    z-index: 1;
 80→}
 81→
 82→.brand::after {
 83→    content: '';
 84→    display: block;
 85→    width: 32px;
 86→    height: 2px;
 87→    background: var(--accent-amber);
 88→    margin-top: 16px;
 89→    opacity: 0.5;
 90→}
 91→
 92→.panel-title {
 93→    font-family: var(--font-serif);
 94→    font-size: clamp(2rem, 4vw, 2.8rem);
 95→    font-weight: 500;
 96→    font-style: italic;
 97→    max-width: 420px;
 98→    line-height: 1.25;
 99→    letter-spacing: -0.02em;
100→    margin: 0 0 24px;
101→    position: relative;
102→    z-index: 1;
103→    color: var(--text-heading);
104→}
105→
106→.panel-copy {
107→    font-family: var(--font-serif);
108→    font-size: 1.1rem;
109→    color: var(--text-body);
110→    max-width: 380px;
111→    line-height: 1.75;
112→    margin: 0 0 32px;
113→    position: relative;
114→    z-index: 1;
115→}
116→
117→.panel-details {
118→    display: flex;
119→    align-items: center;
120→    gap: 20px;
121→    font-family: var(--font-ui);
122→    font-size: 0.72rem;
123→    color: var(--text-muted);
124→    letter-spacing: 0.08em;
125→    text-transform: uppercase;
126→    position: relative;
127→    z-index: 1;
128→}
129→
130→.panel-details::before {
131→    content: '';
132→    display: inline-block;
133→    width: 4px;
134→    height: 4px;
135→    background: var(--accent-amber);
136→    border-radius: 50%;
137→    opacity: 0.6;
138→}
139→
140→/* ── Right Panel: Form Area ── */
141→.auth-form-panel {
142→    display: flex;
143→    align-items: center;
144→    justify-content: center;
145→    padding: 48px;
146→    background: var(--bg-primary);
147→}
148→
149→.auth-form-card {
150→    width: 100%;
151→    max-width: 400px;
152→    display: flex;
153→    flex-direction: column;
154→    gap: 28px;
155→    background: var(--bg-card);
156→    border: 1px solid var(--border-card);
157→    border-radius: 12px;
158→    padding: 40px 36px;
159→    box-shadow: var(--shadow-card-sm);
160→    animation: slideUp 0.5s cubic-bezier(0.16, 1, 0.3, 1) both;
161→}
162→
163→@keyframes slideUp {
164→    from {
165→        opacity: 0;
166→        transform: translateY(16px);
167→    }
168→    to {
169→        opacity: 1;
170→        transform: translateY(0);
171→    }
172→}
173→
174→.form-title {
175→    font-family: "Playfair Display", serif;
176→    font-size: 1.5rem;
177→    font-weight: 600;
178→    letter-spacing: -0.02em;
179→    color: var(--text-heading);
180→    margin-bottom: 4px;
181→}
182→
183→.form-subtitle {
184→    font-family: var(--font-serif);
185→    color: var(--text-body);
186→    margin: 0;
187→    font-size: 0.95rem;
188→    font-style: italic;
189→    line-height: 1.5;
190→}
191→
192→/* ── Form Styles ── */
193→.auth-form {
194→    display: flex;
195→    flex-direction: column;
196→    gap: 20px;
197→}
198→
199→.form-field {
200→    display: flex;
201→    flex-direction: column;
202→    gap: 8px;
203→}
204→
205→.form-field label {
206→    font-family: var(--font-ui);
207→    font-size: 0.7rem;
208→    font-weight: 600;
209→    color: var(--text-muted);
210→    letter-spacing: 0.12em;
211→    text-transform: uppercase;
212→}
213→
214→.auth-input {
215→    font-family: var(--font-ui);
216→    width: 100%;
217→    border: 1px solid var(--border-card);
218→    background: var(--bg-primary);
219→    padding: 14px 16px;
220→    border-radius: 8px;
221→    font-size: 0.95rem;
222→    color: var(--text-primary);
223→    box-sizing: border-box;
224→    transition:
225→        border-color 0.2s ease,
226→        box-shadow 0.2s ease,
227→        background-color 0.2s ease;
228→}
229→
230→.auth-input::placeholder {
231→    color: var(--text-faint);
232→    font-style: italic;
233→}
234→
235→.auth-input:hover {
236→    border-color: var(--border-light);
237→}
238→
239→.auth-input:focus {
240→    outline: none;
241→    border-color: var(--accent-amber);
242→    box-shadow: 0 0 0 3px rgba(212, 168, 83, 0.12);
243→    background: var(--bg-primary);
244→}
245→
246→/* Password field with toggle */
247→.input-with-action {
248→    position: relative;
249→    display: flex;
250→    align-items: center;
251→}
252→
253→.input-with-action .auth-input {
254→    padding-right: 72px;
255→}
256→
257→.show-toggle {
258→    position: absolute;
259→    right: 12px;
260→    background: var(--bg-pill);
261→    border: none;
262→    font-family: var(--font-ui);
263→    font-size: 0.68rem;
264→    font-weight: 600;
265→    letter-spacing: 0.04em;
266→    text-transform: uppercase;
267→    color: var(--text-muted);
268→    cursor: pointer;
269→    padding: 6px 10px;
270→    border-radius: 4px;
271→    transition:
272→        background-color 0.15s ease,
273→        color 0.15s ease;
274→}
275→
276→.show-toggle:hover {
277→    background: var(--bg-hover);
278→    color: var(--accent-amber);
279→}
280→
281→.show-toggle:focus-visible {
282→    outline: 2px solid var(--accent-amber);
283→    outline-offset: 2px;
284→}
285→
286→/* Length counter for email */
287→.length-counter {
288→    position: absolute;
289→    right: 12px;
290→    top: 50%;
291→    transform: translateY(-50%);
292→    font-family: var(--font-ui);
293→    font-size: 0.68rem;
294→    color: var(--text-muted);
295→    pointer-events: none;
296→}
297→
298→/* ── Buttons ── */
299→.primary-button {
300→    display: inline-flex;
301→    align-items: center;
302→    justify-content: center;
303→    gap: 10px;
304→    width: 100%;
305→    padding: 14px 20px;
306→    border-radius: 8px;
307→    border: none;
308→    background: var(--text-heading);
309→    color: var(--bg-primary);
310→    font-family: var(--font-ui);
311→    font-size: 0.88rem;
312→    font-weight: 600;
313→    letter-spacing: 0.02em;
314→    cursor: pointer;
315→    transition:
316→        transform 0.15s ease,
317→        box-shadow 0.2s ease,
318→        background-color 0.2s ease;
319→    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
320→}
321→
322→.primary-button:hover:not(:disabled) {
323→    transform: translateY(-1px);
324→    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
325→}
326→
327→.primary-button:active:not(:disabled) {
328→    transform: translateY(0);
329→}
330→
331→.primary-button:disabled {
332→    opacity: 0.5;
333→    cursor: not-allowed;
334→    box-shadow: none;
335→}
336→
337→.button-label {
338→    display: inline-block;
339→}
340→
341→.button-spinner {
342→    width: 14px;
343→    height: 14px;
344→    border-radius: 50%;
345→    border: 2px solid rgba(255, 255, 255, 0.3);
346→    border-top-color: #fff;
347→    animation: spin 0.7s linear infinite;
348→}
349→
350→@keyframes spin {
351→    to { transform: rotate(360deg); }
352→}
353→
354→.secondary-button {
355→    width: 100%;
356→    display: inline-flex;
357→    align-items: center;
358→    justify-content: center;
359→    padding: 13px 18px;
360→    border-radius: 8px;
361→    border: 1px solid var(--border-card);
362→    background: transparent;
363→    color: var(--text-secondary);
364→    font-family: var(--font-ui);
365→    font-size: 0.88rem;
366→    font-weight: 500;
367→    cursor: pointer;
368→    transition:
369→        border-color 0.2s ease,
370→        background-color 0.2s ease,
371→        color 0.2s ease;
372→}
373→
374→.secondary-button:hover:not(:disabled) {
375→    border-color: var(--accent-amber);
376→    background: rgba(212, 168, 83, 0.04);
377→    color: var(--accent-amber);
378→}
379→
380→.secondary-button:disabled {
381→    opacity: 0.5;
382→    cursor: not-allowed;
383→}
384→
385→/* ── Captcha ── */
386→.captcha-container {
387→    display: flex;
388→    justify-content: center;
389→    padding: 4px 0;
390→}
391→
392→/* ── Footer Link ── */
393→.auth-footer {
394→    display: flex;
395→    align-items: center;
396→    justify-content: center;
397→    gap: 6px;
398→    padding-top: 8px;
399→    border-top: 1px solid var(--border-card);
400→    color: var(--text-muted);
401→    font-size: 0.85rem;
402→}
403→
404→.link-button {
405→    background: none;
406→    border: none;
407→    color: var(--accent-amber);
408→    font-family: var(--font-ui);
409→    font-weight: 600;
410→    font-size: 0.85rem;
411→    cursor: pointer;
412→    padding: 0;
413→    transition: color 0.15s ease;
414→}
415→
416→.link-button:hover {
417→    color: var(--text-heading);
418→    text-decoration: underline;
419→    text-underline-offset: 3px;
420→}
421→
422→.link-button:focus-visible {
423→    outline: 2px solid var(--accent-amber);
424→    outline-offset: 2px;
425→    border-radius: 4px;
426→}
427→
428→/* ── Messages ── */
429→.form-message {
430→    padding: 12px 14px;
431→    border-radius: 8px;
432→    font-family: var(--font-ui);
433→    font-size: 0.85rem;
434→    font-weight: 500;
435→    border: 1px solid transparent;
436→    animation: fadeIn 0.3s ease;
437→}
438→
439→@keyframes fadeIn {
440→    from { opacity: 0; transform: translateY(-4px); }
441→    to { opacity: 1; transform: translateY(0); }
442→}
443→
444→.form-message.error {
445→    background: var(--color-danger-bg);
446→    color: var(--color-danger);
447→    border-color: rgba(220, 38, 38, 0.2);
448→}
449→
450→.form-message.success {
451→    background: var(--color-success-bg);
452→    color: var(--color-success);
453→    border-color: rgba(22, 163, 74, 0.2);
454→}
455→
456→/* ══════════════════════════════════════════════════════════════════════════
457→   RESPONSIVE BREAKPOINTS
458→   ══════════════════════════════════════════════════════════════════════════ */
459→
460→@media (prefers-reduced-motion: reduce) {
461→    .auth-form-card {
462→        animation: none;
463→    }
464→    .auth-panel::before,
465→    .auth-panel::after {
466→        animation: none;
467→    }
468→    .primary-button,
469→    .secondary-button,
470→    .auth-input,
471→    .show-toggle {
472→        transition: none;
473→    }
474→}
