 18→/* ── Left Panel: Brand Story ── */
 19→.auth-panel {
 20→    position: relative;
 21→    display: flex;
 22→    flex-direction: column;
 23→    justify-content: center;
 24→    padding: 64px 72px;
 25→    background: var(--bg-card);
 26→    border-right: 1px solid var(--border-card);
